// Helpers
export const getPFToolsBySubcat = (sub) =>
  PERSONAL_FINANCE_TOOLS.filter(t => sub === 'all' || t.subcategory === sub)

export const getPFToolById = (id) =>
  PERSONAL_FINANCE_TOOLS.find(t => t.id === id)

export const searchPFTools = (query, sub = 'all') => {
  const q = query.toLowerCase()
  return PERSONAL_FINANCE_TOOLS.filter(t =>
    (sub === 'all' || t.subcategory === sub) &&
    (t.name.toLowerCase().includes(q) ||
     t.subcategory.toLowerCase().includes(q) ||
     t.type.toLowerCase().includes(q) ||
     t.users.some(u => u.toLowerCase().includes(q)))
  )
}
